mapper.select:
select * from ( select distinct INSTANCE_ID as taskId,HISTORY_ID as id, -1 as nodeId,nodeName,cronExpress, source_type as sourceType,source_table_name as sourceTableName, source_table_project as sourceTableProject,target_type as targetType,target_table_name as targetTableName, target_table_project as targetTableProject,to_char(CREATE_TIME_node ,'yyyy-mm-dd HH24:mi:ss') as createTime,to_char(BEGIN_RUN_TIME,'yyyy-mm-dd HH24:mi:ss') as beginRunningTime, to_char(finish_time,'yyyy-mm-dd HH24:mi:ss') as finishTime,task_total_time as taskTotalTime,TASK_AVERAGE_TRAFFIC as taskAverageTraffic, RECORD_WRITING_SPEED as recordWritingSpeed ,READ_RECORDS as readRecords ,READ_FAILURE_RECORDS as readFailureRecords, (READ_RECORDS - READ_FAILURE_RECORDS) as writeRecords, case when status is null then 1 else status end as synchronizationStatus from( select mne.*,mn.*,t2.* from( select * from( select distinct node_name as nodeName,NODE_TYPE,CRON_EXPRESS as cronExpress,CREATE_TIME as CREATE_TIME_node ,ROW_NUMBER() over(partition by node_name order by CREATE_TIME desc) as num from m_node mne where NODE_TYPE = 23
and upper(NODE_NAME) like upper('%${nodeNameInput}%')
) where num =1 ) mne left join ( select m1.*,ROW_NUMBER() over(partition by INSTANCE_ID||HISTORY_ID order by BEGIN_RUN_TIME desc) as num from m_flow m1 where BEGIN_RUN_TIME >= TO_DATE(#{taskOpenDate}, 'yyyy-mm-dd HH24:mi:ss') and FINISH_TIME <= TO_DATE(#{taskEndDate}, 'yyyy-mm-dd HH24:mi:ss') and node_type =23 ) mn on mne.nodeName = mn.node_name left join (select * from (select t1.*, ROW_NUMBER() over(partition by TASK_ID order by MESSGAE_INSERT_TIME desc) as num from task_run_analyze t1 ) where num = 1 union all select * from (select t1.*, ROW_NUMBER() over(partition by id order by MESSGAE_INSERT_TIME desc) as num from task_run_analyze t1 where id is not null ) where num = 1 ) t2 on mn.INSTANCE_ID ||mn.HISTORY_ID = t2.task_id||t2.id
1 = 1
))
